import React from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import { ROUTES } from '../utils/constants';
import '../styles/sidebar.css';

const NAV_ITEMS = [
  { label: 'Dashboard',        path: ROUTES.DASHBOARD,  icon: '🏠', exact: true },
  { label: 'Resume Analysis',  path: ROUTES.RESUME,     icon: '📄' },
  { label: 'Coding Practice',  path: ROUTES.CODING,     icon: '💻' },
  { label: 'Mock Interview',   path: ROUTES.INTERVIEW,  icon: '🎤' },
  { label: 'Career Guidance',  path: ROUTES.CAREER,     icon: '🧭' },
  { label: 'Skill Gap',        path: ROUTES.SKILL_GAP,  icon: '📊' },
];

function Sidebar({ isOpen, onClose }) {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = async () => {
    await logout();
    navigate(ROUTES.LOGIN, { replace: true });
  };

  const initials = user?.fullName
    ? user.fullName.split(' ').map((n) => n[0]).join('').toUpperCase().slice(0, 2)
    : 'U';

  return (
    <>
      {/* Backdrop for mobile */}
      {isOpen && (
        <div
          className="sidebar-backdrop"
          onClick={onClose}
          aria-hidden="true"
        />
      )}

      <aside
        className={`sidebar ${isOpen ? 'sidebar--open' : ''}`}
        aria-label="Main navigation"
      >
        {/* Brand header */}
        <div className="sidebar__header">
          <div className="sidebar__brand">
            <span className="sidebar__brand-icon">🎯</span>
            <span className="sidebar__brand-name">
              CareerPilot <strong>AI</strong>
            </span>
          </div>
          {/* Close button — mobile only */}
          <button
            className="sidebar__close"
            onClick={onClose}
            aria-label="Close navigation"
          >
            ✕
          </button>
        </div>

        {/* User profile strip */}
        <div className="sidebar__profile">
          <div className="sidebar__avatar">{initials}</div>
          <div className="sidebar__profile-info">
            <p className="sidebar__profile-name">{user?.fullName}</p>
            <span className="sidebar__profile-role">{user?.role}</span>
          </div>
        </div>

        <hr className="sidebar__divider" />

        {/* Navigation items */}
        <nav className="sidebar__nav" role="navigation">
          <p className="sidebar__nav-label">MAIN MENU</p>
          <ul className="sidebar__nav-list">
            {NAV_ITEMS.map((item) => (
              <li key={item.path}>
                <NavLink
                  to={item.path}
                  end={item.exact}
                  className={({ isActive }) =>
                    `sidebar__nav-item ${isActive ? 'sidebar__nav-item--active' : ''}`
                  }
                  onClick={onClose}
                >
                  <span className="sidebar__nav-icon">{item.icon}</span>
                  <span className="sidebar__nav-label-text">{item.label}</span>
                </NavLink>
              </li>
            ))}
          </ul>
        </nav>

        {/* Spacer pushes logout to bottom */}
        <div className="sidebar__spacer" />

        {/* Logout button */}
        <div className="sidebar__footer">
          <button className="sidebar__logout-btn" onClick={handleLogout}>
            <span>🚪</span>
            <span>Sign Out</span>
          </button>
        </div>
      </aside>
    </>
  );
}

export default Sidebar;
